PythonJavaScript <pre><code>class Animal:
    def __init__(self, name: str):
        self.name = name

    def speak(self) -&gt; str:
        return f"{self.name} speaks"


class Dog(Animal):
    def speak(self) -&gt; str:
        return f"{self.name} barks"


d = Dog("Rex")
print(d.speak())  # Rex barks
print(isinstance(d, Animal))  # True
</code></pre> <pre><code>class Animal {
    constructor(name) {
        this.name = name;
    }

    speak() {
        return `${this.name} speaks`;
    }
}

class Dog extends Animal {
    speak() {
        return `${this.name} barks`;
    }
}

const d = new Dog("Rex");
console.log(d.speak());         // Rex barks
console.log(d instanceof Animal); // true
</code></pre>

PythonJavaScript <pre><code>import asyncio

async def fetch_data(url: str) -&gt; dict:
    await asyncio.sleep(1)  # simulated I/O
    return {"url": url, "data": "..."}

async def main():
    result = await fetch_data("https://example.com")
    print(result)

asyncio.run(main())
</code></pre> <pre><code>async function fetchData(url) {
    const response = await fetch(url);  // real browser/Node API
    const data = await response.json();
    return data;
}

async function main() {
    const result = await fetchData("https://example.com");
    console.log(result);
}

main();
// Alternatively with .then():
// fetchData(url).then(data =&gt; console.log(data)).catch(err =&gt; console.error(err));
</code></pre>
